import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { Lesson } from '../../core/models';

/**
 * LearnLoop lesson viewer — renders lesson content. On init it calls
 * ApiService.viewLesson(id) so the lesson is marked complete-on-view
 * (idempotent) and course progress is refreshed.
 */
@Component({
  selector: 'app-lesson-viewer',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './lesson-viewer.component.html',
  styleUrl: './lesson-viewer.component.css',
})
export class LessonViewerComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly marked = signal(false);
  readonly progressPct = signal<number>(40);

  readonly lesson = signal<Lesson | null>({
    id: 'l1',
    moduleId: 'm1',
    order: 1,
    title: 'What is HTML?',
    content:
      'HTML (HyperText Markup Language) is the standard language for creating web pages. It describes the structure of a page using a series of elements that tell the browser how to display content.\n\nEvery HTML document starts with a <!DOCTYPE html> declaration and is built from nested elements such as headings, paragraphs, lists, links, and images.\n\nIn the next lesson we will look at how individual elements and their tags work together to give a page meaning and structure.',
    viewed: true,
  });

  courseId = '';
  lessonId = '';

  constructor(private api: ApiService, private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.courseId = this.route.snapshot.paramMap.get('id') ?? '';
    this.lessonId = this.route.snapshot.paramMap.get('lessonId') ?? '';

    this.loading.set(true);
    this.error.set(null);
    this.api.getLesson(this.lessonId).subscribe({
      next: (lesson) => {
        this.lesson.set(lesson);
        this.loading.set(false);
        // Complete-on-view: idempotent upsert, returns updated progress.
        this.api.viewLesson(this.lessonId).subscribe({
          next: (p) => {
            this.marked.set(true);
            this.progressPct.set(p.progressPct);
          },
          error: () => {},
        });
      },
      error: () => {
        this.error.set('Could not load this lesson. Please try again.');
        this.loading.set(false);
      },
    });
  }

  paragraphs(content: string): string[] {
    return content.split('\n').filter((p) => p.trim().length > 0);
  }
}
